33	const BASE_PREMIUM: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
41	
42	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
43	const BLOCK_SIZE = 3;
44	const BLOCK_PREMIUM = 60;
45	const CURSE_SURCHARGE_RATE = 0.5;
46	const HIGH_ENCHANTMENT_THRESHOLD = 5;
47	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
48	const LOYALTY_THRESHOLD_YEARS = 2;
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
51	const DEDUCTIBLE = 100;
52	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
53	const FULL_REIMBURSEMENT_RATE = 1;
54	const CLAIM_HALF_REIMBURSEMENT_RATE = 0.5;
55	const INSURANCE_CAP_MULTIPLIER = 2;
56	
57	const INSURANCE_VALUE: Record<string, number> = {
58	  sword: 1000,
59	  rune: 250,
60	  amulet: 600,
61	};
62	
63	function countByType(items: { type: string }[]): Record<string, number> {
64	  const counts: Record<string, number> = {};
65	  for (const item of items) {
66	    counts[item.type] = (counts[item.type] || 0) + 1;
67	  }
68	  return counts;
69	}
70	
71	function calculateBasePremium(items: Item[]): number {
72	  const typeCounts = countByType(items);
73	
74	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
75	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
76	      ? BLOCK_PREMIUM
77	      : count * BASE_PREMIUM[type];
78	    return total + premium;
79	  }, 0);
80	}
81	
82	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
83	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
84	    ? basePremium * LOYALTY_DISCOUNT_RATE
85	    : 0;
86	}
87	
88	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
89	  return (customer.quoteNumber ?? 1) >= 2
90	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
91	    : 0;
92	}
93	
94	function calculateItemSurcharges(items: Item[]): number {
95	  return items.reduce((total, item) => {
96	    const itemBasePremium = BASE_PREMIUM[item.type];
97	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
98	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
99	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
100	      : 0;
101	    return total + curseSurcharge + enchantmentSurcharge;
102	  }, 0);
103	}
104	
105	function calculateInsuranceCap(policyItems: Item[]): number {
106	  const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
107	  return insuranceSum * INSURANCE_CAP_MULTIPLIER;
108	}
109	
110	function validateDamageCounts(damages: Damage[], policyItems: Item[]): void {
111	  const damageCounts = countByType(damages);
112	  const policyCounts = countByType(policyItems);
113	  for (const [type, count] of Object.entries(damageCounts)) {
114	    if (count > (policyCounts[type] || 0)) {
115	      throw new Error(`Damages exceed insured item count for type: ${type}`);
116	    }
117	  }
118	}
119	
120	function calculateDamageReimbursement(damage: Damage, policyItems: Item[]): number {
121	  const matchingItem = policyItems.find(item => item.type === damage.type);
122	  const hasHighEnchantment = matchingItem !== undefined && (matchingItem.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
123	  const reimbursementRate = hasHighEnchantment ? CLAIM_HALF_REIMBURSEMENT_RATE : FULL_REIMBURSEMENT_RATE;
124	  return Math.max(damage.amount * reimbursementRate - DEDUCTIBLE, 0);
125	}
126	
127	function calculateClaimPayout(damages: Damage[], policyItems: Item[]): number {
128	  return damages.reduce((sum, damage) => sum + calculateDamageReimbursement(damage, policyItems), 0);
129	}
130	
131	export function processScenario(scenario: Scenario): unknown[] {
132	  const results: unknown[] = [];
133	
134	  for (const step of scenario.steps) {
135	    if (step.type === "quote") {
136	      const items = step.items!;
137	      const basePremium = calculateBasePremium(items);
138	      const itemSurcharges = calculateItemSurcharges(items);
139	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
140	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
141	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
142	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
143	      results.push({ premium });
144	    } else if (step.type === "claim") {
145	      const policyItems = scenario.steps[step.policy!].items!;
146	      validateDamageCounts(step.damages!, policyItems);
147	
148	      const cap = calculateInsuranceCap(policyItems);
149	      const totalPayout = calculateClaimPayout(step.damages!, policyItems);
150	      const payout = Math.min(totalPayout, cap);
151	      const remainingCap = cap - payout;
152	      results.push({ payout, remainingCap });
153	    }
154	  }
155	
156	  return results;
157	}
